"""Datasets for files generated by src/data/build_training_dataset.py."""

from __future__ import annotations

import csv
from dataclasses import dataclass
from pathlib import Path
from typing import Dict, Iterable, List, Optional

import numpy as np
import torch
from torch import Tensor
from torch.utils.data import Dataset


@dataclass(frozen=True)
class LabelStats:
    mean: float
    std: float

    def normalize(self, value: Tensor) -> Tensor:
        return (value - self.mean) / self.std

    def denormalize(self, value: Tensor) -> Tensor:
        return value * self.std + self.mean


def read_manifest(manifest_path: Path) -> List[Dict[str, str]]:
    with manifest_path.open("r", encoding="utf-8", newline="") as f:
        return list(csv.DictReader(f))


def resolve_window_path(raw_path: str, export_dir: Path) -> Path:
    path = Path(raw_path)
    if path.exists():
        return path
    marker = "training_exports/"
    text = raw_path.replace("\\", "/")
    if marker in text:
        rel = text.split(marker, 1)[1]
        candidate = export_dir / rel
        if candidate.exists():
            return candidate
    candidate = export_dir / path.name
    if candidate.exists():
        return candidate
    return path


def compute_label_stats(rows: Iterable[Dict[str, str]]) -> LabelStats:
    labels = np.asarray([float(row["label_heart_rate"]) for row in rows], dtype=np.float32)
    mean = float(np.mean(labels))
    std = float(np.std(labels))
    if not np.isfinite(std) or std < 1e-6:
        std = 1.0
    return LabelStats(mean=mean, std=std)


class RadarWindowDataset(Dataset):
    """Fixed-window radar heart-rate dataset.

    Each item contains:
        x_time: FloatTensor, shape (7, 256)
        x_freq: FloatTensor, shape (7, 129)
        y: normalized heart-rate label, shape ()
        y_bpm: raw BPM label, shape ()
    """

    def __init__(
        self,
        export_dir: str | Path,
        split: str,
        label_stats: Optional[LabelStats] = None,
        datasets: Optional[set[str]] = None,
    ) -> None:
        self.export_dir = Path(export_dir)
        self.split = split
        manifest_path = self.export_dir / "manifest.csv"
        rows = read_manifest(manifest_path)
        self.rows = [
            row
            for row in rows
            if row.get("split") == split and (datasets is None or row.get("dataset") in datasets)
        ]
        if not self.rows:
            raise ValueError(f"No rows found for split={split!r} in {manifest_path}")
        self.label_stats = label_stats or compute_label_stats(self.rows)

    def __len__(self) -> int:
        return len(self.rows)

    def __getitem__(self, index: int) -> Dict[str, Tensor | str]:
        row = self.rows[index]
        path = resolve_window_path(row["window_path"], self.export_dir)
        with np.load(path, allow_pickle=False) as data:
            x_time = torch.from_numpy(data["x_time"].astype(np.float32, copy=False))
            x_freq = torch.from_numpy(data["x_freq"].astype(np.float32, copy=False))
        y_bpm = torch.tensor(float(row["label_heart_rate"]), dtype=torch.float32)
        y = self.label_stats.normalize(y_bpm)
        return {
            "x_time": x_time,
            "x_freq": x_freq,
            "y": y,
            "y_bpm": y_bpm,
            "dataset": row.get("dataset", ""),
            "group_key": row.get("group_key", ""),
            "sample_tag": row.get("sample_tag", ""),
            "window_path": str(path),
        }


def build_datasets(
    export_dir: str | Path,
    datasets: Optional[set[str]] = None,
) -> tuple[RadarWindowDataset, RadarWindowDataset, RadarWindowDataset, LabelStats]:
    export_dir = Path(export_dir)
    rows = read_manifest(export_dir / "manifest.csv")
    train_rows = [
        row
        for row in rows
        if row.get("split") == "train" and (datasets is None or row.get("dataset") in datasets)
    ]
    if not train_rows:
        raise ValueError("Cannot compute label stats: no train rows found")
    stats = compute_label_stats(train_rows)
    train = RadarWindowDataset(export_dir, "train", label_stats=stats, datasets=datasets)
    val = RadarWindowDataset(export_dir, "val", label_stats=stats, datasets=datasets)
    test = RadarWindowDataset(export_dir, "test", label_stats=stats, datasets=datasets)
    return train, val, test, stats
